import { Component, signal } from '@angular/core';
import { AXGaugeChartComponent } from '@acorex/charts/gauge-chart';
import { AXGaugeChartOption } from '@acorex/charts/gauge-chart';
import { AXGaugeChartValue } from '@acorex/charts/gauge-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Gauge Chart</h2>
      <ax-gauge-chart 
        [value]="showcaseValue()" 
        [options]="showcaseOptions()"
      />
      <div class="gauge-info">
        <p>Performance metrics with threshold indicators</p>
      </div>
    </div>
  `,
  imports: [AXGaugeChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
      text-align: center;
    }
    .gauge-info {
      margin-top: 1rem;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class GaugeChartShowcaseComponent {
  showcaseValue = signal<AXGaugeChartValue>(78);

  showcaseOptions = signal<AXGaugeChartOption>({
    minValue: 0,
    maxValue: 100,
    width: 400,
    height: 200,
    gaugeWidth: 30,
    cornerRadius: 8,
    showValue: true,
    label: 'Performance Score',
    animationDuration: 1500,
    animationEasing: 'ease-in-out',
    thresholds: [
      { value: 30, color: '#ef4444', label: 'Low' },
      { value: 60, color: '#f59e0b', label: 'Medium' },
      { value: 85, color: '#10b981', label: 'High' }
    ]
  });
}
